/**
 * Activation hook: Create custom database table.
 */
function wp_custom_auth_activate() {
    global $wpdb;
    $table_name = $wpdb->prefix . WP_CUSTOM_AUTH_TABLE;
    $charset_collate = $wpdb->get_charset_collate();

    $sql = "CREATE TABLE $table_name (
        id bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT,
        username varchar(60) NOT NULL UNIQUE,
        email varchar(100) NOT NULL UNIQUE,
        password varchar(255) NOT NULL,
        created_at datetime DEFAULT CURRENT_TIMESTAMP NOT NULL,
        PRIMARY KEY  (id)
    ) $charset_collate;";

    require_once( ABSPATH . 'wp-admin/includes/upgrade.php' );
    dbDelta( $sql );

    add_option( 'wp_custom_auth_db_version', WP_CUSTOM_AUTH_DB_VERSION );
}
register_activation_hook( __FILE__, 'wp_custom_auth_activate' );

