/**
 * Helper function to check if a custom user is logged in.
 *
 * @return bool True if a custom user is logged in, false otherwise.
 */
function wp_custom_auth_is_logged_in() {
    return isset( $_SESSION[ WP_CUSTOM_AUTH_SESSION_KEY ] ) && ! empty( $_SESSION[ WP_CUSTOM_AUTH_SESSION_KEY ] );
}

/**
 * Helper function to get the current logged-in custom user's data.
 *
 * @return object|null User object if logged in, null otherwise.
 */
function wp_custom_auth_get_current_user() {
    if ( ! wp_custom_auth_is_logged_in() ) {
        return null;
    }

    global $wpdb;
    $table_name = $wpdb->prefix . WP_CUSTOM_AUTH_TABLE;
    $user_id = (int) $_SESSION[ WP_CUSTOM_AUTH_SESSION_KEY ];

    return $wpdb->get_row( $wpdb->prepare( "SELECT id, username, email, created_at FROM $table_name WHERE id = %d", $user_id ) );
}

