            } else {
                $message = '<p class="wp-custom-auth-message error">Registration failed. Please try again.</p>';
            }
        } else {
            $message = '<ul class="wp-custom-auth-message error">';
            foreach ( $errors as $error ) {
                $message .= '<li>' . esc_html( $error ) . '</li>';
            }
            $message .= '</ul>';
        }
